import{_ as e,o as d,c as a,ae as o}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Google Ads Data & Reporting","description":"","frontmatter":{"title":"Google Ads Data & Reporting","slug":"google-ads-data-reporting"},"headers":[],"relativePath":"marketer-hub/google-ads-data-reporting.md","filePath":"marketer-hub/google-ads-data-reporting.md"}'),r={name:"marketer-hub/google-ads-data-reporting.md"};function n(c,t,i,s,h,l){return d(),a("div",null,[...t[0]||(t[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>After connecting Google Ads to Branch, data will seamlessly flow between the two to measure your campaigns&#39; performance. It is helpful to know what kinds of data are passed to each platform to properly compare campaigns and optimize future campaigns. The Branch Dashboard will also populate with helpful reports for campaign measurement.</p><h2 id="mapping-between-google-ads-branch" tabindex="-1">Mapping between Google Ads &amp; Branch <a class="header-anchor" href="#mapping-between-google-ads-branch" aria-label="Permalink to &quot;Mapping between Google Ads &amp; Branch&quot;">​</a></h2><h4 id="campaign-data-mapping" tabindex="-1">Campaign data mapping <a class="header-anchor" href="#campaign-data-mapping" aria-label="Permalink to &quot;Campaign data mapping&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Branch data</th><th>Google data</th><th>Definition</th><th>Possible values</th></tr></thead><tbody><tr><td><code>~campaign_id</code></td><td><code>campaign_id</code></td><td>The numeric campaign ID of the campaign that produced the ad event. This value is guaranteed unique.</td><td>Google Ads Campaign ID</td></tr><tr><td><code>~campaign</code></td><td><code>campaign_name</code></td><td>The advertiser-defined campaign name of the campaign that produced the ad event. This value is not guaranteed unique.</td><td>Google Ads Campaign, Name</td></tr><tr><td><code>~ad_format</code></td><td><code>ad_type</code></td><td>The type of ad that resulted in the ad event. This value can be used to distinguish between various types of inventory as follows.</td><td>ClickToDownload, AppDeepLink, AppDeepLinkContinue, Unknown</td></tr><tr><td><code>~channel</code></td><td><code>network_type</code></td><td>This field will identify the Google Ads advertising network the ad event occurred on.</td><td>Display, GoogleTV, Cross-network, Search, Youtube, Unpopulated</td></tr><tr><td><code>~country</code></td><td><code>country</code></td><td>User’s country code.</td><td>2-letter country code</td></tr><tr><td><code>~secondary_publisher</code></td><td><code>network_subtype</code></td><td>This field will identify the “subtype” of the Google Ads advertising network the ad event occurred on. The possible values vary by primary network type.</td><td>Display, GoogleTV, Cross-network, GoogleSearch, SearchPartners, YouTubeVideos, Unpopulated</td></tr><tr><td><code>~tags</code></td><td><code>campaign_type</code></td><td>This field will identify the type of campaign that produced the ad event.</td><td>UAC, UACe, Search, Display, Video, Shopping</td></tr><tr><td><code>~ad_set_name</code></td><td><code>ad_group_name</code></td><td>The advertiser-defined ad group name that produced the ad event.</td><td>Google Ads Ad Group Name</td></tr><tr><td><code>~ad_set_id</code></td><td><code>ad_group_id</code></td><td>The numeric ID of the ad group that produced with the ad event.</td><td>Google Ads Ad Group ID</td></tr><tr><td><code>~ad_id</code></td><td><code>creative_id</code></td><td>The numeric ID of the creative ad unit that produced the ad event. Only provided when campaign_type is not UAC.</td><td>Google Ads Creative ID</td></tr><tr><td><code>~keyword</code></td><td><code>keyword</code></td><td>The search keyword associated with the ad event. Only provided when network_type is Search and campaign_type is not UAC.</td><td>Google Ads Keyword</td></tr></tbody></table><h4 id="event-mapping" tabindex="-1">Event mapping <a class="header-anchor" href="#event-mapping" aria-label="Permalink to &quot;Event mapping&quot;">​</a></h4><p>Once you begin tracking events through the Branch SDK, you can select which events to import in Google Ads. Google Ads has pre-defined events that map to pre-defined Branch events, listed below.</p><p>Regardless of campaign type, Branch will forward in-app events to Google Ads for campaign optimization. In addition, Branch will receive attribution data for rich analysis in the Branch Dashboard.</p><table tabindex="0"><thead><tr><th>Branch Event</th><th>Google Event</th></tr></thead><tbody><tr><td><code>INSTALL</code></td><td><code>first_open</code></td></tr><tr><td><code>OPEN</code></td><td><code>session_start</code></td></tr><tr><td><code>PURCHASE</code></td><td><code>in_app_purchase</code></td></tr><tr><td><code>VIEW_ITEM</code></td><td><code>view_item</code></td></tr><tr><td><code>VIEW_ITEMS</code></td><td><code>view_item_list</code></td></tr><tr><td><code>SEARCH</code></td><td><code>view_search_results</code></td></tr><tr><td><code>ADD_TO_CART</code></td><td><code>add_to_cart</code></td></tr><tr><td><code>PURCHASE</code></td><td><code>ecommerce_purchase</code></td></tr><tr><td>&#39;REINSTALL&#39;</td><td>&#39; reinstall_open&#39;</td></tr><tr><td><em>custom</em></td><td><code>custom</code></td></tr></tbody></table><h4 id="event-metadata-mapping" tabindex="-1">Event Metadata Mapping <a class="header-anchor" href="#event-metadata-mapping" aria-label="Permalink to &quot;Event Metadata Mapping&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Branch metadata</th><th>Google Ads metadata</th><th>Description</th></tr></thead><tbody><tr><td><code>content_items[].$sku</code></td><td><code>item_id</code></td><td>The ID of the item being referenced in an app event. Represented as it&#39;s SKU number; e,g, <code>SKU_12345</code></td></tr><tr><td><code>custom_data.end_date</code></td><td><code>end_date</code></td><td>The date when the event ended. The value should be in YYYY-MM-DD format.</td></tr><tr><td><code>custom_data.google_business_vertical</code></td><td><code>google_business_vertical</code></td><td>The vertical ID associated with the <a href="https://developers.google.com/google-ads/api/reference/data/verticals?hl=en" target="_blank" rel="noreferrer">Google&#39;s list of verticals</a> used for targeting or excluding categories of placements.</td></tr><tr><td><code>custom_data.item_location_id</code></td><td><code>item_location_id</code></td><td>The location associated with the event. If possible, set to the Google Place ID that corresponds to the associated item; e.g. <code>L_12345</code> . Can also be overridden to a custom location ID string.</td></tr><tr><td><code>custom_data.origin</code></td><td><code>origin</code></td><td>The origin of the feed; possible values: - UNSPECIFIED - UNKNOWN - USER - GOOGLE</td></tr><tr><td><code>custom_data.search_term</code></td><td><code>search_term</code></td><td>The term that was searched for; e.g. <code>t-shirts</code></td></tr><tr><td><code>custom_data.start_date</code></td><td><code>start_date</code></td><td>The date when the event started. The value should be in YYYY-MM-DD format.</td></tr><tr><td><code>event_data_currency</code></td><td><code>currency_code</code></td><td>The three-character <a href="https://www.iso.org/iso-4217-currency-codes.html" target="_blank" rel="noreferrer">ISO 4217 code</a>; e.g. <code>USD</code> for United States Dollar.</td></tr><tr><td><code>revenue</code></td><td><code>value</code></td><td>The monetary value of the conversion event in float format.</td></tr></tbody></table><h2 id="branch-dashboard-reports" tabindex="-1">Branch Dashboard Reports <a class="header-anchor" href="#branch-dashboard-reports" aria-label="Permalink to &quot;Branch Dashboard Reports&quot;">​</a></h2><h4 id="available-dimensions-to-compare-by-for-uac" tabindex="-1">Available Dimensions to Compare by for UAC <a class="header-anchor" href="#available-dimensions-to-compare-by-for-uac" aria-label="Permalink to &quot;Available Dimensions to Compare by for UAC&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Dimension</th><th>Supported?</th></tr></thead><tbody><tr><td>Clicks</td><td>✅ Yes</td></tr><tr><td>Cost</td><td>✅ Yes</td></tr><tr><td>Impressions</td><td>✅ Yes</td></tr><tr><td>Feature</td><td>✅ Yes</td></tr><tr><td>Channel</td><td>✅ Yes</td></tr><tr><td>Campaign</td><td>✅ Yes</td></tr><tr><td>Tags</td><td>❌ No<code>*</code></td></tr><tr><td>Stage</td><td>❌ No</td></tr><tr><td>Ad Partner</td><td>✅ Yes</td></tr><tr><td>OS</td><td>✅ Yes</td></tr><tr><td>Platform</td><td>✅ Yes<code>**</code></td></tr><tr><td>Secondary Publisher</td><td>✅ Yes</td></tr><tr><td>Ad Set Name</td><td>✅ Yes</td></tr><tr><td>Ad Name</td><td>❌ No</td></tr><tr><td>Creative Name</td><td>❌ No</td></tr><tr><td>Keyword</td><td>❌ No</td></tr><tr><td>Last Touch Type</td><td>✅ Yes</td></tr><tr><td>Link ID</td><td>❌ No</td></tr><tr><td>Country</td><td>✅ Yes<code>**</code></td></tr></tbody></table><p><code>*</code>Used to identify the type of campaign, but not customizable. Ex. <code>ACI</code>/<code>ACE</code><br><code>**</code>Not available on clicks or impressions, but available on attributed activity.</p><h4 id="cost-metrics-data" tabindex="-1">Cost Metrics Data <a class="header-anchor" href="#cost-metrics-data" aria-label="Permalink to &quot;Cost Metrics Data&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Analytics tag</th><th>Description</th><th>Used for</th></tr></thead><tbody><tr><td>Cost</td><td>Total cost (spend)</td><td>Understanding the total amount spent for dimensions (analytics tags, user data, time range)</td></tr><tr><td>eCPI</td><td>cost / installs</td><td>Normalizing spend per install, to understand the average price of an install across networks or over time</td></tr><tr><td>eCPC</td><td>cost / clicks</td><td>Normalizing spend per click, to understand the average price of an click across networks or over tim</td></tr><tr><td>eCPM</td><td>cost / (impressions / 1000)</td><td>Normalizing spend per thousand impressions, to understand the average price of 1000 impressions across networks or over time</td></tr><tr><td>eCPA</td><td>cost / purchases [web and app]</td><td>Normalizing spend per purchase, to understand the average price of a purchase across networks or over time</td></tr><tr><td>Return On Investment (ROI)</td><td>(revenue-cost / cost) * 100</td><td>Deriving return on investment, to understand the percentage &quot;profit&quot; made on ad spend</td></tr><tr><td>Return On Ad Spend (ROAS)</td><td>(revenue / cost) * 100</td><td>Deriving return on investment by understanding the percentage revenue multiple for a given unit of spend</td></tr></tbody></table><h4 id="engagement-metrics" tabindex="-1">Engagement Metrics <a class="header-anchor" href="#engagement-metrics" aria-label="Permalink to &quot;Engagement Metrics&quot;">​</a></h4><p>You can view data for click-through engagement (<a href="https://support.google.com/google-ads/answer/10048752" target="_blank" rel="noreferrer">Engaged View</a>) conversion metrics for Google Adwords through Dashboard Reports or exports:</p><table tabindex="0"><thead><tr><th>Report/Export</th><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Dashboard Report</td><td><code>touch subtype</code></td><td><code>engaged_view</code></td></tr><tr><td>Dashboard Custom Exports</td><td>Column</td><td>Touch Subtype</td></tr><tr><td>Custom Exports API</td><td><code>fields</code></td><td><code>last_attributed_touch_data_tilde_touch_subtype</code></td></tr></tbody></table>',20)])])}const m=e(r,[["render",n]]);export{g as __pageData,m as default};
